HRESULT MRFGenericUtils::CreateGSMToolUnderGivenFeature(CATBaseUnknown_var pIPrtPart, CATIGSMTool * & pIGsmTool, CATBoolean bOrdered, CATUnicodeString iGSName)
{
	HRESULT rc = E_FAIL;
	if (NULL != pIPrtPart)
	{
		pIGsmTool = NULL;

		CATIMmiMechanicalFeature_var spMechFeatOnMainTool = pIPrtPart;
		if (NULL_var != spMechFeatOnMainTool)
		{
			//Get container
			CATIMmiPrtContainer_var spPrtCont = NULL_var;
			rc = spMechFeatOnMainTool->GetPrtContainer(spPrtCont);
			if (SUCCEEDED(rc) && spPrtCont != NULL_var)
			{
				CATIMmiUseSetFactory_var spMechanicalRootFactory = spPrtCont;
				if (spPrtCont != NULL_var)
				{
					CATIMmiMechanicalFeature_var spGSMTool;
					if (bOrdered)
						rc = spMechanicalRootFactory->CreateOrderedGeometricalSet(iGSName, spMechFeatOnMainTool, spGSMTool);
					else
						rc = spMechanicalRootFactory->CreateGeometricalSet(iGSName, spMechFeatOnMainTool, spGSMTool);

					if (SUCCEEDED(rc))
					{
						rc = spGSMTool->QueryInterface(IID_CATIGSMTool, (void**) &(pIGsmTool));
						MRFProdStrServices::SetSynchroGraphicProperties(spMechFeatOnMainTool);
					}
				}
			}
		}

	}
	return rc;
}

void MRFGenericUtils::ReframeOnObject(CATBaseUnknown_var ispObject)
{
	CATViewer * pViewer = CATViewer::GetCurrentViewer();
	if (NULL != pViewer && NULL_var != ispObject)
	{
		CATBody_var spBody = ispObject;
		if(spBody == NULL_var)
			GetBodyOfObject(ispObject, spBody);
		if (NULL_var != spBody)
		{
			CATMathBox MathBoxOnBody = spBody->GetBoundingBox();

			CATMathPoint pPointOnCenter;
			CATMathPoint pointOnHigh;

			MathBoxOnBody.GetBoxCenter(pPointOnCenter);
			MathBoxOnBody.GetHighLimit(pointOnHigh);

			float radius = (float)pPointOnCenter.DistanceTo(pointOnHigh);
			if (radius < 5.f)
				radius = 5.f;

			CAT3DBoundingSphere p3DBoundingSphere(pPointOnCenter, radius);
			CAT3DViewer* p3DViewer = (CAT3DViewer*)pViewer;
			if (NULL != p3DViewer)
			{
				p3DViewer->ReframeOn(p3DBoundingSphere);
				p3DViewer->Draw();
			}
		}
	}
}

CATBoolean MRFGenericUtils::UpdateFeature(CATIMmiMechanicalFeature_var ispFeatureObject, CATIMmiMechanicalFeature_var ispParentFeature, CATBoolean ibCreateMode)
{
	CATBoolean bUpdate = CATFalse;
	HRESULT rc = E_FAIL;
	CATIBasicTool_var spBasicTool = ispParentFeature;
	CATIGSMTool_var spGSMToolLoc = ispParentFeature;
	if (NULL_var != spGSMToolLoc)
	{
		int type = 0;
		spGSMToolLoc->GetType(type);
		if (type == 1 || type == 0)
		{
			CATIGSMUseProceduralView_var spProceduralView = ispFeatureObject;
			if (NULL_var != spProceduralView)
			{
				rc = spProceduralView->InsertInProceduralView(ispParentFeature);

				if (SUCCEEDED(rc))
					bUpdate = CATTrue;
			}
		}
	}
	if (!bUpdate)
	{
		CATIMmiUseBasicInsertion_var spBasicInsertion = ispFeatureObject;
		if (NULL_var != spBasicInsertion)
		{
			if (NULL_var != spBasicTool)
			{
				rc = spBasicInsertion->InsertInside(ispParentFeature);
			}
			else
			{
				rc = spBasicInsertion->InsertAfter(ispParentFeature);
				CATIMmiMechanicalFeature_var spFather;
				ispParentFeature->GetMechanicalFather(spFather);
				if (NULL_var != spFather)
				{
					ispParentFeature = NULL_var;
					ispParentFeature = spFather;
				}
			}

			if (SUCCEEDED(rc))
				bUpdate = CATTrue;
		}
	}
	if (bUpdate)
	{
		CATIModelEvents_var spMyFeatureModelEvents = ispFeatureObject;
		if (NULL_var != spMyFeatureModelEvents)
		{
			/*int mode = 0;
			if (ibCreateMode)
			{
				CATCreate Notif(ispFeatureObject, ispParentFeature);
				spMyFeatureModelEvents->Dispatch(Notif);
				mode = 1;
			}
			else*/
			{
				CATModify Notif(ispFeatureObject);
				spMyFeatureModelEvents->Dispatch(Notif);
			}

			CATIVisProperties * pVisProperties = NULL;
			rc = ispFeatureObject->QueryInterface(IID_CATIVisProperties, (void**)& pVisProperties);
			if (SUCCEEDED(rc) && NULL != pVisProperties)
			{
				CATVisPropertiesValues VisPropValues;
				VisPropValues.SetShow(CATShowAttr);

				rc = pVisProperties->SetPropertiesAtt(VisPropValues, CATVPShow, CATVPGlobalType);
				pVisProperties->Release(); pVisProperties = NULL;
			}
			CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(ispParentFeature, 1, 0);
		}
	}

	return bUpdate;
}


