void MRFGenericUtils::HideShowObject(CATBaseUnknown_var ispObjectToHideOrShow, int iShowIndex)
{
	if (NULL_var != ispObjectToHideOrShow)
	{
		CATIVisProperties * pVisProperties = NULL;
		ispObjectToHideOrShow->QueryInterface(IID_CATIVisProperties, (void**)& pVisProperties);
		if (NULL != pVisProperties)
		{
			CATVisPropertiesValues VisPropValues;
			if (SUCCEEDED(pVisProperties->GetPropertiesAtt(VisPropValues, CATVPShow, CATVPGlobalType)))
			{

				CATShowAttribut ShowAttr = CATShowAttr;
				VisPropValues.GetShow(ShowAttr);
				pVisProperties->ResetPropertiesAtt(CATVPShow, CATVPGlobalType);
				CATBoolean bProceed = CATFalse;

				if (0 == iShowIndex && CATShowAttr == ShowAttr)
				{
					VisPropValues.SetShow(CATNoShowAttr);
					bProceed = CATTrue;
				}
				else if (1 == iShowIndex && CATNoShowAttr == ShowAttr)
				{
					VisPropValues.SetShow(CATShowAttr);
					bProceed = CATTrue;
				}
				else if (2 == iShowIndex)
				{
					if (CATNoShowAttr == ShowAttr)
						VisPropValues.SetShow(CATShowAttr);
					else if (CATShowAttr == ShowAttr)
						VisPropValues.SetShow(CATNoShowAttr);

					bProceed = CATTrue;
				}
				if (bProceed)
				{

					pVisProperties->SetPropertiesAtt(VisPropValues, CATVPShow, CATVPGlobalType);

					CATIModelEvents_var MyFeatureModelEventsTool = ispObjectToHideOrShow;
					if (NULL_var != MyFeatureModelEventsTool)
					{
						CATModify NotifModify(ispObjectToHideOrShow);
						MyFeatureModelEventsTool->Dispatch(NotifModify);
					}

					CATIRedrawEvent_var spRedrawEvent = ispObjectToHideOrShow;
					if (NULL_var != spRedrawEvent) spRedrawEvent->Redraw();

				}
			}
			pVisProperties->Release(); pVisProperties = NULL;
		}
	}
}

CATBoolean MRFGenericUtils::CenterGraphOnObject()
{
	CATFrmLayout * pLayout = CATFrmLayout::GetCurrentLayout();
	if (NULL == pLayout) return TRUE;

	CATFrmWindow * pCurrentWindow = pLayout->GetCurrentWindow();
	if (NULL == pCurrentWindow) return TRUE;

	if (1 != pCurrentWindow->IsAKindOf("CATFrmNavigGraphicWindow")) return TRUE;

	CATFrmNavigGraphicWindow * pFrmNavigGraphicWindow = (CATFrmNavigGraphicWindow*)pCurrentWindow;

	CATNavigBox * pNavigBox = NULL;
	pNavigBox = pFrmNavigGraphicWindow->GetNavigBox();

	if (NULL == pNavigBox) return TRUE;

	CATCafCenterGraph CenterGraphObj;
	CenterGraphObj.CenterGraph("OnHSO", pNavigBox);

	return TRUE;
}

