CATBaseUnknown_var MRFGenericUtils::FindFeatureUnderGeomSet(const CATBaseUnknown_var &bodyRequestOfGSMTool, const CATUnicodeString &nameToCompare, CATBaseUnknown_var &outPut)
{
	CATIBodyRequest_var bodyReq_Loc;
	CATBaseUnknown_var result;

	if (outPut != NULL_var) //If output already found return;
		return NULL_var;

	if (!!bodyRequestOfGSMTool)
	{
		CATListValCATBaseUnknown_var *listOfBodies = NULL;
		CATINavigateObject_var spNavigObject_GSMTool = bodyRequestOfGSMTool;
		if (!!spNavigObject_GSMTool)
			listOfBodies = spNavigObject_GSMTool->GetChildren();
		//bodyRequestOfGSMTool->GetDirectBodies(listOfBodies);
		if (outPut == NULL_var)
		{
			if (listOfBodies)
			{
				for (int i = 1; i <= listOfBodies->Size(); i++)
				{
					bodyReq_Loc = (CATIBodyRequest_var)(*listOfBodies)[i];
					if (!!bodyReq_Loc)
					{
						CATUnicodeString nameOfFeat = MRFGenericUtils::GetAliasName(bodyReq_Loc);
						if (nameOfFeat.Compare(nameToCompare))
						{
							outPut = (*listOfBodies)[i];
							return outPut;
						}
						else
							FindFeatureUnderGeomSet(bodyReq_Loc, nameToCompare, outPut);
					}
					else
					{
						CATBaseUnknown_var spFoundFeat = (*listOfBodies)[i];
						CATUnicodeString nameOfFeat = MRFGenericUtils::GetAliasName(spFoundFeat);
						if (nameOfFeat.Compare(nameToCompare))
						{
							outPut = (*listOfBodies)[i];
							return outPut;
						}
					}
				}

			}
		}
		else
			return outPut;

	}

	return outPut;
}

CATUnicodeString MRFGenericUtils::GetParamValue(const CATICkeParm_var & spCkeParam)
{
	CATUnicodeString parmValue;
	if (!!spCkeParam)
	{
		CATUnicodeString strValue = spCkeParam->Show();
		CATICkeType_var spCkeType = spCkeParam->Type();
		if (NULL_var != spCkeType)
		{
			if (spCkeType->IsaBoolean() || spCkeType->IsaInteger() || spCkeType->IsaReal() || spCkeType->IsaString())
			{
				parmValue = strValue;
			}
			else
			{
				CATICkeMagnitude_var spMagnitude(spCkeType);
				if (NULL_var != spMagnitude)
				{
					CATICkeUnit_var spUnit(spMagnitude->CurrentUnit());
					CATUnicodeString strSymbol = spUnit->Symbol();

					int src = strValue.SearchSubString(strSymbol);
					parmValue = strValue.SubString(0, src);

				}
				else
				{
					double val = 0.;
					int cnv = strValue.ConvertToNum(&val);
					if (1 == cnv)
						parmValue.BuildFromNum(val);
					else
						parmValue = strValue;
				}
			}
		}
	}

	return parmValue;
}

CATBaseUnknown_var MRFGenericUtils::GetFactoryFromFeature(CATIMmiMechanicalFeature_var spMechFeat, MRFGenericUtils::FactoryType factType)
{
	if (!!spMechFeat)
	{
		CATIMmiPrtContainer_var spPrtCont;
		spMechFeat->GetPrtContainer(spPrtCont);

		if (!!spPrtCont)
		{
			if (factType == MRFGenericUtils::FactoryType::CkeRelFact)
			{
				CATICkeRelationFactory_var spRelFact = spPrtCont;
				if (!!spRelFact)
					return spRelFact;
			}
			else if (factType == MRFGenericUtils::FactoryType::CkeParmFact)
			{
				CATICkeParmFactory_var spParmFact = spPrtCont;
				if (!!spParmFact)
					return spParmFact;
			}
			else if (factType == MRFGenericUtils::FactoryType::GeoFact)
			{
				CATGeoFactory_var spGeoact = spPrtCont;
				if (!!spGeoact)
					return spGeoact;
			}
		}
	}

	return NULL_var;
}

