CATBaseUnknown_var MRFGenericUtils::FindFeatureUnderCATPart(const CATIMmiUsePrtPart_var &spPart, CATUnicodeString featureName)
{
	CATBaseUnknown_var spOutput;
	if (!spPart)
		return spOutput;

	CATIPartRequest_var spPartReq = spPart;
	if (spPartReq != NULL_var)
	{
		CATListValCATBaseUnknown_var spListOfBodies;
		spPartReq->GetAllBodies("MfDefault3DView", spListOfBodies);

		if (spListOfBodies.Size() > 0)
		{
			for (int i = 1; i <= spListOfBodies.Size() && spOutput == NULL_var; i++)
			{
				CATIBodyRequest_var spBodyReqTool = spListOfBodies[i];
				if (spBodyReqTool != NULL_var)
					FindFeatureUnderGeomSet(spBodyReqTool,featureName, spOutput);
			}
		}
	}

	return spOutput;
}

CATIMmiMechanicalFeature_var MRFGenericUtils::GetSegmentCuttingAxis(CATIMmiMechanicalFeature_var & spSegmentCuttingSurface)
{
	CATUnicodeString strSegmentAxis = CATMsgCatalog::BuildMessage("MRFSegmentPartitionHeader", "MRFDynamicSegment.SegmentCuttingAxis.Name");

	CATIMmiMechanicalFeature_var spAxisFeature;
	if (NULL_var != spSegmentCuttingSurface)
	{
		CATIGSMUseRotate_var spRotate = spSegmentCuttingSurface;
		if (NULL_var != spRotate)
		{
			spRotate->GetAxis(spAxisFeature);
		}

		if (NULL_var != spAxisFeature)
		{
			CATIAlias_var spAlias = spAxisFeature;
			if (NULL_var != spAlias)
			{
				CATUnicodeString strAliasName = spAlias->GetAlias();
				if (2 != strAliasName.Compare(strSegmentAxis))
					spAxisFeature = NULL_var;
			}
		}
		if (NULL_var == spAxisFeature)
		{
			CATIMmiMechanicalFeature_var spFather;
			spSegmentCuttingSurface->GetMechanicalFather(spFather);
			if (NULL_var != spFather)
			{
				FindFeatureUnderGeomSet(spFather, strSegmentAxis, spAxisFeature);
			}
		}
	}
	return spAxisFeature;
}